    public static long solve(long m, long n, long[][] waitCost) {
        int rows = (int) m;
        int cols = (int) n;
        long[][][] dist = new long[rows][cols][2];
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                dist[i][j][0] = Long.MAX_VALUE;
                dist[i][j][1] = Long.MAX_VALUE;
            }
        }
        dist[0][0][1] = 1;
        PriorityQueue<long[]> pq = new PriorityQueue<>(Comparator.comparingLong(a -> a[0]));
        pq.offer(new long[]{1, 0, 0, 1});
        int[] dx = {0, 1};
        int[] dy = {1, 0};
        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            long cost = current[0];
            int i = current[1];
            int j = current[2];
            int p = (int) current[3];
            if (i == rows - 1 && j == cols - 1 && p == 0) {
                return cost;
            }
            if (cost > dist[i][j][p]) {
                continue;
            }
            if (p == 1) {
                for (int d = 0; d < 2; d++) {
                    int ni = i + dx[d];
                    int nj = j + dy[d];
                    if (ni >= 0 && ni < rows && nj >= 0 && nj < cols) {
                        long newCost = cost + (long) ((ni + 1) * (nj + 1));
                        int new_p = 0;
                        if (newCost < dist[ni][nj][new_p]) {
                            dist[ni][nj][new_p] = newCost;
                            pq.offer(new long[]{newCost, ni, nj, new_p});
                        }
                    }
                }
            } else {
                long newCost = cost + waitCost[i][j];
                int new_p = 1;
                if (newCost < dist[i][j][new_p]) {
                    dist[i][j][new_p] = newCost;
                    pq.offer(new long[]{newCost, i, j, new_p});
                }
            }
        }
        return -1;
    }
}
